final:
module top_module(
  input [7:0] dividend,
  input [7:0] num2,
  input [1:0] op,
  output reg [7:0] result
);always @(*)
begin
  case(op)
    2'b00: result = dividend + num2;
    2'b01: result = dividend - num2;
    2'b10: result = dividend * num2;
    2'b11: result = dividend / num2;
  endcase
end

endmodule
